class Solution(object):
    def minTime(self, n, edges, k):
        def count_components(t):
            parent = list(range(n))
            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            comps = n
            for u, v, time in edges:
                if time > t:
                    pu, pv = find(u), find(v)
                    if pu != pv:
                        parent[pu] = pv
                        comps -= 1
            return comps

        if count_components(0) >= k:
            return 0

        times = sorted(set(e[2] for e in edges))
        lo, hi = 0, len(times) - 1
        ans = times[-1]
        while lo <= hi:
            mid = (lo + hi) // 2
            t = times[mid]
            if count_components(t) >= k:
                ans = t
                hi = mid - 1
            else:
                lo = mid + 1
        return ans
